 rejectCallbacks = [] // pending \u4E0B\uFF0C\u5B58\u50A8\u5931\u8D25\u7684\u56DE\u8C03\n\n  constructor(fn) {\n    const resolveHandler = (value) => {\n      if (this.state === 'pending') {\n        this.state = 'fulfilled'\n        this.value = value\n        // \u72B6\u6001\u53D8\u5316\u540E\uFF0C\u51FD\u6570\u6267\u884C\n        this.resolveCallbacks.forEach(fn => fn(this.value))\n      }\n    }\n\n    const rejectHandler = (reason) => {\n      if (this.state === 'pending') {\n        this.state = 'rejected'\n        this.reason = reason\n        // \u72B6\u6001\u53D8\u5316\u540E\uFF0C\u51FD\u6570\u6267\u884C\n        this.rejectCallbacks.forEach(fn => fn(this.reason))\n      }\n    }\n\n    try {\n      fn(resolveHandler, rejectHandler)\n    } catch (err) {\n      resolveHandler(err)\n    }\n  }\n\n  then(fn1, fn2) {\n    // \u5F53 pending \u4E0B\uFF0Cfn1,fn2 \u5B58\u50A8\u5230 callbacks \u4E2D\n    fn1 = typeof fn1 === 'function' ? fn1 : (v) => v\n    fn2 = typeof fn2 === 'function' ? fn2 : (e) => e\n\n    // \u51FD\u6570\u8FD8\u6CA1\u6267\u884C\uFF0C\u8FD4\u56DE\u65B0\u7684 promise\n    if (this.state === 'pending') {\n      const p1 = new MyPromise((resolve, reject) => {\n        this.resolveCallbacks.push(() => {\n          try {\n            const newValue = fn1(this.value)\n            resolve(newValue)\n          } catch (err) {\n            reject(err)\n          }\n        })\n        this.rejectCallbacks.push(() => {\n          try {\n            const newReason = fn1(this.reason)\n            reject(newReason)\n          } catch (err) {\n            reject(err)\n          }\n        })\n      })\n      return p1\n    }\n\n    // fn1 \u51FD\u6570\u6267\u884C\uFF0C\u8FD4\u56DE\u65B0\u7684 promise\n    if (this.state === 'fulfilled') {\n      const p1 = new MyPromise((resolve, reject) => {\n        try {\n          const newValue = fn1(this.value)\n          resolve(newValue)\n        } catch (err) {\n          reject(err)\n        }\n      })\n      return p1\n    }\n\n    // fn2 \u51FD\u6570\u6267\u884C\uFF0C\u8FD4\u56DE\u65B0\u7684 promise\n    if (this.state === 'rejected') {\n      const p1 = new MyPromise((resolve, reject) => {\n        try {\n          const newReason = fn2(this.reason)\n          reject(newReason)\n        } catch (err) {\n          reject(err)\n        }\n      })\n      return p1\n    }\n  }\n\n  // catch \u5C31\u662F then \u7684\u4E00\u4E2A\u8BED\u6CD5\u7CD6\uFF0C\u7B80\u5355\u6A21\u5F0F\n  catch(fn) {\n    return this.then(null, fn)\n  }\n}\n\n// \u5168\u5C40\u9759\u6001\u65B9\u6CD5\nMyPromise.resolve = function (value) {\n  return new MyPromise((resolve, reject) => resolve(value))\n}\n\nMyPromise.reject = function (reason) {\n  return new MyPromise((resolve, reject) => reject(reason))\n}\n\nMyPromise.all = function (promiseList = []) {\n  const p1 = new MyPromise((resolve, reject) => {\n    const result = [] // \u5B58\u50A8 promiseList \u6240\u6709\u7684\u7ED3\u679C\n    const length = promiseList.length\n    let resolvedCount = 0\n\n    promiseList.forEach(p => {\n      p.then(data => {\n        result.push(data)\n\n        // resolvedCount \u5FC5\u987B\u5728 then \u91CC\u9762\u505A ++\n        // \u4E0D\u80FD\u4F7F\u7528 foreach \u7684 index\uFF0C\u56E0\u4E3A index \u662F\u540C\u6B65\u7684\n        resolvedCount++\n        if (resolvedCount == length) {\n          // \u5DF2\u7ECF\u5230\u6700\u540E\u4E00\u4E2A\n          resolve(result)\n        }\n      }).catch(err => {\n        reject(err)\n      })\n    })\n  })\n  return p1\n}\n\nMyPromise.race = function (promiseList = []) {\n  let resolved = false // \u6807\u8BB0\n  const p1 = new MyPromise((resolve, reject) => {\n    promiseList.forEach(p => {\n      p.then(data => {\n        if (!resolved) {\n          resolve(data)\n          resolved = true\n        }\n      }).catch(err => {\n        reject(err)\n      })\n    })\n  })\n  return p1\n}\n"})}),"\n",(0,s.jsx)(n.p,{children:"\u6D4B\u8BD5\u4EE3\u7801"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-js",children:"// \u666E\u901A\u8C03\u7528\nconst p1 = new MyPromise((resolve, reject) => {\n  // resolve(100)\n  // reject('\u9519\u8BEF...')\n  setTimeout(() => {\n    resolve(100)\n  }, 1000)\n})\n\n// \u94FE\u5F0F\u8C03\u7528\nconst p11 = p1.then(data1 => {\n  console.log('data1', data1) // data1 100\n  return data1 + 1\n})\nconst p12 = p11.then(data2 => {\n  console.log('data2', data2) // data2 101\n  return data2 + 1\n})\nconst p13 = p12.catch(err => console.error(err))\n\n// api \u8C03\u7528\nconst p2 = MyPromise.resolve(200)\nconst p3 = MyPromise.resolve(300)\nconst p4 = MyPromise.reject('\u9519\u8BEF...')\n// \u4F20\u5165 promise \u6570\u7EC4\uFF0C\u7B49\u5F85\u6240\u6709\u7684\u90FD fulfilled \u540E\uFF0C\u8FD4\u56DE\u65B0\u7684 promise \u5305\u542B\u524D\u9762\u6240\u6709\u7684\u7ED3\u679C\nconst p5 = MyPromise.all([p1, p2, p3])\np5.then(result => console.log('all result', result)) // all result (3)[200, 300, 100]\n// \u4F20\u5165 promise \u6570\u7EC4\uFF0C\u53EA\u8981\u6709\u4E00\u4E2A fulfilled \u5373\u53EF\u8FD4\u56DE\nconst p6 = MyPromise.race([p1, p2, p3])\np6.then(result => console.log('race result', result)) // race result 200\n"})})]})}function d(e={}){let{wrapper:n}={...(0,o.a)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(u,{...e})}):u(e)}},50065:function(e,n,r){r.d(n,{Z:function(){return a},a:function(){return l}});var t=r(67294);let s={},o=t.createContext(s);function l(e){let n=t.useContext(o);return t.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:l(e.components),t.createElement(o.Provider,{value:n},e.children)}}}]);